func (s *service) Cancel(ctx context.Context, input CancelInput) (creditpurchase.Charge, error) {
	if err := input.Validate(); err != nil {
		return creditpurchase.Charge{}, err
	}
	charge, err := s.chargesService.GetByID(ctx, charges.GetByIDInput{ID: input.ChargeID})
	if err != nil {
		return creditpurchase.Charge{}, err
	}
	if charge.Intent.CustomerID != input.CustomerID {
		return creditpurchase.Charge{}, models.NewGenericForbiddenError(fmt.Errorf("charge does not belong to customer"))
	}
	return s.chargesService.ApplyPatches(ctx, ...)
}

func (s *Service) CancelInvoice(ctx context.Context, input billing.CancelInvoiceInput) (billing.StandardInvoice, error) {
	if err := input.Validate(); err != nil {
		return billing.StandardInvoice{}, billing.ValidationError{Err: err}
	}
	return transactionForInvoiceManipulation(ctx, s, input.CustomerID, func(ctx context.Context) (billing.StandardInvoice, error) {
		return s.executeTriggerOnInvoice(ctx, input.Invoice, billing.TriggerVoid)
	})
}

